{"command": "cat > /work/main.go << 'GOEOF'
package main

import (
	"flag"
	"fmt"
	"io"
	"os"
	"strings"
	"time"

	"encoding/json"
)

type ModuleInfo struct {
	Path      string      `json:"Path"`
	Version   string      `json:"Version"`
	Time      string      `json:"Time"`
	Indirect  bool        `json:"Indirect"`
	Main      bool        `json:"Main"`
	Update    *ModuleInfo `json:"Update"`
	Replace   *ModuleInfo `json:"Replace"`
	Dir       string      `json:"Dir"`
	GoMod     string      `json:"GoMod"`
	GoVersion string      `json:"GoVersion"`
	Error     *struct {
		Err string `json:"Err"`
	} `json:"Error"`
}

func padCenter(s string, width int) string {
	if len(s) >= width {
		return s
	}
	totalPad := width - len(s)
	left := totalPad / 2
	right := totalPad - left
	return strings.Repeat(" ", left) + s + strings.Repeat(" ", right)
}

func main() {
	ci := flag.Bool("ci", false, "Non-zero exit code when at least one outdated dependency was found")
	direct := flag.Bool("direct", false, "List only direct modules")
	style := flag.String("style", "default", "Output style, pass 'markdown' for a Markdown table")
	update := flag.Bool("update", false, "List only modules with updates")
	flag.Parse()

	decoder := json.NewDecoder(os.Stdin)
	var modules []ModuleInfo

	for {
		var m ModuleInfo
		if err := decoder.Decode(&m); err == io.EOF {
			break
		} else if err != nil {
			fmt.Fprintf(os.Stderr, "%s %s\n", time.Now().Format("2006/01/02 15:04:05"), err.Error())
			os.Exit(0)
		}

		// Skip main module
		if m.Main {
			continue
		}

		modules = append(modules, m)
	}

	if len(modules) == 0 {
		return
	}

	// Filter
	var filtered []ModuleInfo
	for _, m := range modules {
		if *direct && m.Indirect {
			continue
		}
		if *update && m.Update == nil {
			continue
		}
		filtered = append(filtered, m)
	}

	if len(filtered) == 0 {
		return
	}

	// Compute column widths
	headers := []string{"MODULE", "VERSION", "NEW VERSION", "DIRECT", "VALID TIMESTAMPS"}
	minWidths := []int{
		len(headers[0]),
		len(headers[1]),
		len(headers[2]),
		len(headers[3]),
		len(headers[4]),
	}

	hasOutdated := false

	for _, m := range filtered {
		newVersion := ""
		validTimestamps := true

		if m.Update != nil {
			newVersion = m.Update.Version
			// Check if timestamps are valid
			currentTime, err1 := time.Parse(time.RFC3339, m.Time)
			updatedTime, err2 := time.Parse(time.RFC3339, m.Update.Time)
			if err1 == nil && err2 == nil {
				if updatedTime.Before(currentTime) {
					validTimestamps = false
				}
			}
			hasOutdated = true
		}

		directStr := "false"
		if !m.Indirect {
			directStr = "true"
		}
		validStr := "false"
		if validTimestamps {
			validStr = "true"
		}

		values := []string{m.Path, m.Version, newVersion, directStr, validStr}
		for i, v := range values {
			if len(v) > minWidths[i] {
				minWidths[i] = len(v)
			}
		}
	}

	totalWidth := 0
	for _, w := range minWidths {
		totalWidth += w + 2 // padding
	}

	// Build table
	var rows [][]string
	for _, m := range filtered {
		newVersion := ""
		validTimestamps := true

		if m.Update != nil {
			newVersion = m.Update.Version
			currentTime, err1 := time.Parse(time.RFC3339, m.Time)
			updatedTime, err2 := time.Parse(time.RFC3339, m.Update.Time)
			if err1 == nil && err2 == nil {
				if updatedTime.Before(currentTime) {
					validTimestamps = false
				}
			}
		}

		directStr := "false"
		if !m.Indirect {
			directStr = "true"
		}
		validStr := "false"
		if validTimestamps {
			validStr = "true"
		}

		row := []string{m.Path, m.Version, newVersion, directStr, validStr}
		rows = append(rows, row)
	}

	if *style == "markdown" {
		// Header row
		var hdrParts []string
		for i, h := range headers {
			hdrParts = append(hdrParts, "|" + padCenter(h, minWidths[i]+2) + "|")
		}
		fmt.Println(strings.Join(hdrParts, ""))

		// Separator
		var sepParts []string
		for _, w := range minWidths {
			sepParts = append(sepParts, "|" + strings.Repeat("-", w+2) + "|")
		}
		fmt.Println(strings.Join(sepParts, ""))

		// Data rows
		for _, row := range rows {
			var parts []string
			for i, v := range row {
				parts = append(parts, "|" + padCenter(v, minWidths[i]+2) + "|")
			}
			fmt.Println(strings.Join(parts, ""))
		}
	} else {
		// Default style
		// Build column widths with padding
		colWidths := make([]int, len(headers))
		for i, w := range minWidths {
			colWidths[i] = w + 2
		}

		// Top border
		var topParts []string
		for _, w := range colWidths {
			topParts = append(topParts, strings.Repeat("-", w))
		}
		topBorder := "+" + strings.Join(topParts, "+") + "+"
		fmt.Println(topBorder)

		// Header row
		var hdrParts []string
		for i, h := range headers {
			hdrParts = append(hdrParts, "|" + padCenter(h, colWidths[i]) + "|")
		}
		fmt.Println(strings.Join(hdrParts, ""))

		// Separator after header
		fmt.Println(topBorder)

		// Data rows
		for _, row := range rows {
			var parts []string
			for i, v := range row {
				parts = append(parts, "|" + padCenter(v, colWidths[i]) + "|")
			}
			fmt.Println(strings.Join(parts, ""))
		}

		// Bottom border
		fmt.Println(topBorder)
	}

	if *ci && hasOutdated {
		os.Exit(1)
	}
}
GOEOF"}

