			module:          m.Path,
			version:         m.Version,
			newVersion:      newVersion,
			direct:          directStr,
			validTimestamps: validStr,
		})

		values := []string{m.Path, m.Version, newVersion, directStr, validStr}
		for i, v := range values {
			minWidths[i] = max(minWidths[i], len(v)+2) // +2 for left+right padding space
		}
	}

	if *style == "markdown" {
		// Header row
		var hdrParts []string
		for i, h := range headers {
			hdrParts = append(hdrParts, "|" + padCenter(h, minWidths[i]) + "|")
		}
		fmt.Println(hdrParts)

		// Separator
		var sepParts []string
		for _, w := range minWidths {
			sepParts = append(sepParts, "|" + fmt.Sprintf("%*s", w, "") + "|")
		}
		// Replace spaces with dashes
		sepLine := ""
		for i, c := range sepParts[0] {
			if c == '|' {
				sepLine += "|"
			} else {
				sepLine += "-"
			}
		}
		// Actually rebuild sep properly
		var sep2 []string
		for _, w := range minWidths {
			sep2 = append(sep2, fmt.Sprintf("|%s|", fmt.Sprintf("%*s", w, "")))
		}
		sepLine = ""
		for _, w := range minWidths {
			sepLine += "|"
			for j := 0; j < w; j++ {
				sepLine += "-"
			}
		}
		sepLine += "|"
		fmt.Println(sepLine)

		// Data rows
		for _, row := range rows {
			var parts []string
			values := []string{row.module, row.version, row.newVersion, row.direct, row.validTimestamps}
			for i, v := range values {
				parts = append(parts, "|" + padLeft(v, minWidths[i]) + "|")
			}
			fmt.Println(parts)
		}
	} else {
		// Default style
		// Top border
		topBorder := "+"
		for _, w := range minWidths {
			topBorder += fmt.Sprintf("%*s%+s", w, "-", "+")
		}
		// That gives +------------------+
		// redo border
		topBorder = ""
		for _, w := range minWidths {
			topBorder += "+"
			for j := 0; j < w; j++ {
				topBorder += "-"
			}
		}
		topBorder += "+"
		fmt.Println(topBorder)

		// Header row (centered)
		headerLine := ""
		for i, h := range headers {
			headerLine += "|" + padCenter(h, minWidths[i]) + "|"
		}
		fmt.Println(headerLine)

		fmt.Println(topBorder)

		// Data rows (left aligned)
		for _, row := range rows {
			line := ""
			values := []string{row.module, row.version, row.newVersion, row.direct, row.validTimestamps}
			for i, v := range values {
				line += "|" + padLeft(v, minWidths[i]) + "|"
			}
			fmt.Println(line)
		}

		fmt.Println(topBorder)
	}

	if *ci && hasOutdated {
		os.Exit(1)
	}
}
GOEOF"}

