func buildCellRow(values []string, widths []string, centered bool) string {
	n := len(values)
	line := "|"
	for i := 0; i < n; i++ {
		content := values[i]
		w := widths[i]
		var cell string
		if centered {
			cell = padCenterCell(content, w)
		} else {
